const item = $input.first().json;
const exec = item.execution || {};
const trig = item.trigger || {};
const wf = item.workflow || {};
const err = exec.error || trig.error || {};
const msg = err.message || (err.cause && err.cause.message) || 'Unknown error';
const node = exec.lastNodeExecuted || (err.node && err.node.name) || 'unknown';
const stack = String(err.stack || (err.cause && err.cause.stack) || '').split('\n').slice(0, 8).join('\n');
const lines = [
  'n8n workflow failed',
  'Workflow: ' + (wf.name || '?'),
  'Node: ' + node,
  'Error: ' + msg,
];
if (exec.id) lines.push('Execution ID: ' + exec.id);
if (exec.url) lines.push('URL: ' + exec.url);
if (stack) lines.push('', stack);
return [{
  json: {
    ntfyTitle: 'n8n: ' + (wf.name || 'workflow') + ' failed',
    ntfyMessage: lines.join('\n'),
    ntfyTags: ['warning', 'skull'],
    ntfyPriority: 4,
  },
}];
